#include <stdio.h>
#include <string.h>

int minFlips(char *s, int x) {
    int n = strlen(s);
    int minFlips = n;
    for (int mask = 0; mask < (1 << n); mask++) {
        char t[n + 1];
        strcpy(t, s);
        for (int i = 0; i < n; i++) {
            if ((mask & (1 << i)) != 0) {
                t[i] = (t[i] == '0') ? '1' : '0';
            }
        }
        if (t[0] == '1' && t[n - 1] == '0') {
            int count = 0;
            for (int i = 0; i < n - 1; i++) {
                if (t[i] == '1' && t[i + 1] == '0') {
                    count++;
                }
            }
            if (count == x) {
                int flips = 0;
                for (int i = 0; i < n; i++) {
                    if (s[i] != t[i]) {
                        flips++;
                    }
                }
                minFlips = (flips < minFlips) ? flips : minFlips;
            }
        }
    }
    return minFlips;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        char s[100];
        scanf("%s", s);
        int x;
        scanf("%d", &x);
        int minFlips = minFlips(s, x);
        if (minFlips == strlen(s)) {
            printf("NO\n");
        } else {
            printf("YES\n");
            printf("%d\n", minFlips);
        }
    }
    return 0;
}

